import java.util.HashMap;

class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

public TreeNode constructTree(int[][] descriptions) {
    HashMap<Integer, TreeNode> nodes = new HashMap<>();
    for (int[] d : descriptions) {
        nodes.put(d[0], new TreeNode(d[0]));
        nodes.put(d[1], new TreeNode(d[1]));
    }

    for (int[] d : descriptions) {
        if (d[2] == 1)
            nodes.get(d[0]).left = nodes.get(d[1]);
        else
            nodes.get(d[0]).right = nodes.get(d[1]);
    }

    return nodes.get(descriptions[0][0]);
}
